template:
const std = @import("std");

pub const WordCount = struct {
    word: []const u8,
    count: u32,
};

fn lessThan(_: void, a: WordCount, b: WordCount) bool {
    if (a.count != b.count) return a.count __SLOT_comparison__ b.count;          // higher count first
    return std.mem.lessThan(u8, a.word, b.word);                 // ties: word asc
}

pub fn topN(alloc: std.mem.Allocator, counts: *std.StringHashMap(u32), n: usize) ![]WordCount {
    var all: std.ArrayList(WordCount) = .empty;
    errdefer all.deinit(alloc);

    var it = counts.__SLOT_iterator__();
    while (it.next()) |entry| {
        try all.append(alloc, .{
            .word = entry.key_ptr.*,
            .count = entry.__SLOT_value_field__.*,
        });
    }

    std.mem.sort(__SLOT_sort_type__, all.items, {}, lessThan);

    const k = if (n < all.items.len) __SLOT_limit__ else all.items.len;
    const out = try alloc.alloc(WordCount, k);
    for (out, 0..) |*c, i| c.* = all.items[i];
    all.deinit(alloc);
    return out;
}
